// Suppress ServiceWorker redirect errors that can surface in headed Chrome when a
// previously-registered /sw.js is redirected (e.g. to /login in test mode).
// These are not caused by the tests themselves and should not fail the suite.
Cypress.on('uncaught:exception', (err) => {
  if (
    err.message.includes('ServiceWorker') ||
    err.message.includes('serviceWorker') ||
    err.message.includes('sw.js')
  ) {
    return false
  }
})

