describe('Running Settings — Profile Section', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.loginWithBypass()
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubSettingsLoaded()
    stubStravaConnected()
    cy.viewport(1280, 720)
  })

  it('profile form renders after loading skeleton disappears', () => {
    stubProfileLoaded()
    cy.visit(SETTINGS_URL)
    // Wait for loading skeleton to disappear
    cy.get(`#${IDS.profile_loading}`).should('not.exist')
    cy.get(`#${IDS.display_name_input}`).should('be.visible')
  })

  it('save profile → shows success message on 200', () => {
    stubProfileLoaded()
    cy.visit(SETTINGS_URL)
    cy.get(`#${IDS.profile_loading}`).should('not.exist')

    cy.intercept('PATCH', PROFILE_API, {
      statusCode: 200,
      body: { data: { display_name: 'Test Runner' }, message: 'Profile updated' },
    }).as('patchProfile')

    cy.get(`#${IDS.display_name_input}`).clear().type('Test Runner')
    cy.get(`#${IDS.profile_save_btn}`).click()

    cy.wait('@patchProfile')
    cy.get(`#${IDS.profile_save_success}`).should('be.visible')
  })

  it('save profile → shows error message on server error (422)', () => {
    stubProfileLoaded()
    cy.visit(SETTINGS_URL)
    cy.get(`#${IDS.profile_loading}`).should('not.exist')

    cy.intercept('PATCH', PROFILE_API, {
      statusCode: 422,
      body: { error: 'Validation failed' },
    }).as('patchProfileError')

    cy.get(`#${IDS.display_name_input}`).clear().type('Bad Input')
    cy.get(`#${IDS.profile_save_btn}`).click()

    cy.wait('@patchProfileError')
    cy.get(`#${IDS.profile_save_error}`).should('be.visible')
  })
})

