// ============================================================
// Push Notifications Toggle
// ============================================================
describe('Running Settings — Push Notifications', () => {
  const PUSH_SUBSCRIPTION_API = RUNNING_ENDPOINTS.PUSH_SUBSCRIPTION

  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.loginWithBypass()
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubProfileLoaded()
    stubStravaConnected()
    cy.viewport(1280, 720)
  })

  it('enable flow → POST subscription object when permission is granted', () => {
    // Start with push disabled
    stubSettingsLoaded({ push_notifications_enabled: false })

    // Use cy.intercept before cy.visit so the stub is in place when the page loads
    cy.intercept('POST', PUSH_SUBSCRIPTION_API, {
      statusCode: 200,
      body: { data: { push_notifications_enabled: true }, message: 'Push subscription saved' },
    }).as('postSubscription')

    // Stub browser push APIs using plain functions (not cy.stub) inside onBeforeLoad
    // cy.stub() cannot be used in onBeforeLoad — it requires the Cypress context which is not
    // available during app initialization. Plain functions are used instead.
    cy.visit(SETTINGS_URL, {
      onBeforeLoad(win) {
        const fakeSubscription = {
          toJSON: () => ({
            endpoint: 'https://fcm.googleapis.com/fcm/send/test-endpoint',
            keys: { p256dh: 'fake-p256dh-key', auth: 'fake-auth-key' },
          }),
        }
        const fakePushManager = {
          subscribe: () => Promise.resolve(fakeSubscription),
          getSubscription: () => Promise.resolve(null),
        }
        const fakeRegistration = { pushManager: fakePushManager }

        // Override only Notification.requestPermission — permission getter is read-only in Chrome
        // and cannot be set directly. The component only calls requestPermission() and checks
        // its return value, so we only need to stub that method.
        win.Notification.requestPermission = () => Promise.resolve('granted')

        // Override serviceWorker so register returns our fake registration
        Object.defineProperty(win.navigator, 'serviceWorker', {
          configurable: true,
          writable: true,
          value: {
            register: () => Promise.resolve(fakeRegistration),
            ready: Promise.resolve(fakeRegistration),
          },
        })
      },
    })

    cy.get(`#${IDS.notifications_loading}`).should('not.exist')

    // Click the push toggle — force true because shadcn Switch may have pointer-events managed
    cy.get(`#${IDS.push_notifications_toggle}`).click({ force: true })
    cy.wait('@postSubscription').then((interception) => {
      expect(interception.request.body).to.have.property('subscription')
      expect(interception.request.body.subscription).to.not.be.null
    })
  })

  it('disable flow → POST { subscription: null } to clear subscription', () => {
    // Start with push already enabled
    stubSettingsLoaded({ push_notifications_enabled: true })

    cy.intercept('POST', PUSH_SUBSCRIPTION_API, {
      statusCode: 200,
      body: { data: { push_notifications_enabled: false }, message: 'Push subscription cleared' },
    }).as('clearSubscription')

    cy.visit(SETTINGS_URL, {
      onBeforeLoad(win) {
        // Stub unsubscribe on an existing subscription — plain functions only in onBeforeLoad
        const fakeExistingSubscription = {
          unsubscribe: () => Promise.resolve(true),
        }
        const fakePushManager = {
          getSubscription: () => Promise.resolve(fakeExistingSubscription),
        }
        const fakeRegistration = { pushManager: fakePushManager }
        Object.defineProperty(win.navigator, 'serviceWorker', {
          configurable: true,
          writable: true,
          value: {
            register: () => Promise.resolve(fakeRegistration),
            ready: Promise.resolve(fakeRegistration),
          },
        })
      },
    })

    cy.get(`#${IDS.notifications_loading}`).should('not.exist')
    // Toggle is currently ON (push_notifications_enabled: true) — clicking turns it off
    cy.get(`#${IDS.push_notifications_toggle}`).click({ force: true })
    cy.wait('@clearSubscription').then((interception) => {
      expect(interception.request.body).to.deep.equal({ subscription: null })
    })
  })

  it('permission denied → shows error element, toggle stays OFF', () => {
    stubSettingsLoaded({ push_notifications_enabled: false })

    cy.visit(SETTINGS_URL, {
      onBeforeLoad(win) {
        // Override only requestPermission — the permission getter is read-only in Chrome.
        // The component calls Notification.requestPermission() and checks the return value.
        win.Notification.requestPermission = () => Promise.resolve('denied')
        const fakePushManager = { getSubscription: () => Promise.resolve(null) }
        const fakeRegistration = { pushManager: fakePushManager }
        Object.defineProperty(win.navigator, 'serviceWorker', {
          configurable: true,
          writable: true,
          value: {
            register: () => Promise.resolve(fakeRegistration),
            ready: Promise.resolve(fakeRegistration),
          },
        })
      },
    })

    cy.get(`#${IDS.notifications_loading}`).should('not.exist')
    cy.get(`#${IDS.push_notifications_toggle}`).click({ force: true })

    // Error message should appear after permission is denied.
    // scrollIntoView is needed because the card container has overflow:hidden which clips
    // the error paragraph from Cypress' visibility check without scrolling.
    cy.get(`#${IDS.push_notifications_error}`).scrollIntoView().should('be.visible')

    // Toggle should remain unchecked (aria-checked="false")
    cy.get(`#${IDS.push_notifications_toggle}`).should('have.attr', 'aria-checked', 'false')
  })

  it('persist after reload → toggle is ON when settings return push_notifications_enabled: true', () => {
    // First load with push enabled
    stubSettingsLoaded({ push_notifications_enabled: true })

    cy.visit(SETTINGS_URL)
    cy.get(`#${IDS.notifications_loading}`).should('not.exist')

    // Toggle should be ON after initial load
    cy.get(`#${IDS.push_notifications_toggle}`).should('have.attr', 'aria-checked', 'true')

    // Simulate a reload — re-stub the settings endpoint before reload
    cy.intercept('GET', SETTINGS_API, {
      statusCode: 200,
      body: {
        data: {
          hr_zones_method: 'max_hr',
          threshold_hr: null,
          notify_post_activity: true,
          notify_weekly_review: true,
          notify_friday_prep: true,
          notify_anomaly: true,
          push_notifications_enabled: true,
        },
        message: 'OK',
      },
    }).as('getSettingsAfterReload')

    cy.reload()
    stubRtUsers()
    stubProfileLoaded()
    stubStravaConnected()
    cy.wait('@getSettingsAfterReload')

    cy.get(`#${IDS.notifications_loading}`).should('not.exist')
    cy.get(`#${IDS.push_notifications_toggle}`).should('have.attr', 'aria-checked', 'true')
  })
})
